firmware_template.source:
#include "pir_sensor.h"
#include <Arduino.h>
#define PIR_PIN 13
static volatile bool _motion=false;
static unsigned long _lastMotion=0;
void IRAM_ATTR _pir_isr(){_motion=true;}
void pir_setup(){pinMode(PIR_PIN,INPUT);attachInterrupt(PIR_PIN,_pir_isr,RISING);Serial.println("[pir] OK");}
void pir_loop(){
  if(_motion){_motion=false;_lastMotion=millis();Serial.println("[pir] Motion!");}
}
bool pir_motion_detected(){return millis()-_lastMotion<5000;}
unsigned long pir_last_motion_time(){return _lastMotion;}
